import SwiftUI

struct BiliUserLevelIcon: View {
    let level: Int
    var width: CGFloat = 27
    var height: CGFloat = 17

    var body: some View {
        if level > 0 {
            let clamped = min(max(level, 1), 6)
            let spec = Self.specs[clamped - 1]
            BiliSVGPathShape(pathData: spec.pathData, viewBoxRect: Self.viewBoxRect)
                .fill(spec.color, style: FillStyle(eoFill: true, antialiased: true))
                .frame(width: width, height: height, alignment: .leading)
                .fixedSize(horizontal: false, vertical: true)
        }
    }

    // Crop to the badge artwork instead of the full 1024x1024 icon font viewport.
    private static let viewBoxRect = CGRect(x: 20, y: 250, width: 955, height: 525)

    private static let specs: [BiliUserLevelSpec] = [
        BiliUserLevelSpec(color: Color(red: 0xBF / 255, green: 0xBF / 255, blue: 0xBF / 255), pathData: BiliUserLevelPaths.level1),
        BiliUserLevelSpec(color: Color(red: 0x95 / 255, green: 0xDD / 255, blue: 0xB2 / 255), pathData: BiliUserLevelPaths.level2),
        BiliUserLevelSpec(color: Color(red: 0x92 / 255, green: 0xD1 / 255, blue: 0xE5 / 255), pathData: BiliUserLevelPaths.level3),
        BiliUserLevelSpec(color: Color(red: 0xFF / 255, green: 0xB3 / 255, blue: 0x7C / 255), pathData: BiliUserLevelPaths.level4),
        BiliUserLevelSpec(color: Color(red: 0xFF / 255, green: 0x6C / 255, blue: 0x00 / 255), pathData: BiliUserLevelPaths.level5),
        BiliUserLevelSpec(color: Color(red: 0xFF / 255, green: 0x00 / 255, blue: 0x00 / 255), pathData: BiliUserLevelPaths.level6),
    ]
}

